// Angular reactive — dynamic options with @for
@Component({
  standalone: true,
  imports: [ReactiveFormsModule, CommonModule],
  template: `
    <select formControlName="country">
      <option value="">— choose —</option>
      @for (c of countries; track c.code) {
        <option [value]="c.code">{{ c.name }}</option>
      }
    </select>
  `,
})
export class CountrySelectComponent {
  countries = [
    { code: 'us', name: 'United States' },
    { code: 'gb', name: 'United Kingdom' },
    { code: 'de', name: 'Germany' },
  ];
  form = new FormGroup({ country: new FormControl('', Validators.required) });
}

@Component({
  standalone: true,
  template: `
    <input type="file" accept="image/*" (change)="onFile($event)" />
    <img [src]="preview()" *ngIf="preview()" alt="preview" />
  `,
})
export class AvatarUploadComponent {
  preview = signal<string | null>(null);

  onFile(event: Event): void {
    const input = event.target as HTMLInputElement;
    const file = input.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      alert('File must be under 5 MB');
      input.value = '';
      return;
    }

    const reader = new FileReader();
    reader.onload = () => this.preview.set(reader.result as string);
    reader.readAsDataURL(file);
  }
}

import { Component, forwardRef } from '@angular/core';
import {
  ControlValueAccessor, NG_VALUE_ACCESSOR,
} from '@angular/forms';

@Component({
  selector: 'app-rating',
  standalone: true,
  providers: [{
    provide: NG_VALUE_ACCESSOR,
    useExisting: forwardRef(() => RatingComponent),
    multi: true,
  }],
  template: `
    @for (star of stars; track star) {
      <button type="button"
        [class.filled]="star <= value"
        (click)="select(star)"
        [disabled]="disabled">★</button>
    }
  `,
})
export class RatingComponent implements ControlValueAccessor {
  stars = [1, 2, 3, 4, 5];
  value = 0;
  disabled = false;

  writeValue(val: number): void { this.value = val ?? 0; }
  registerOnChange(fn: (v: number) => void): void { this.onChange = fn; }
  registerOnTouched(fn: () => void): void { this.onTouched = fn; }
  setDisabledState(isDisabled: boolean): void { this.disabled = isDisabled; }

  private onChange: (v: number) => void = () => {};
  private onTouched: () => void = () => {};

  select(star: number): void {
    this.value = star;
    this.onChange(star);
    this.onTouched();
  }
}

// Usage — treated exactly like a native input
form = new FormGroup({
  rating: new FormControl(0, [Validators.required, Validators.min(1)]),
});

import { Component, inject, signal } from '@angular/core';
import {
  FormBuilder, FormControl, FormGroup,
  ReactiveFormsModule, Validators
} from '@angular/forms';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-register',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="onSubmit()" novalidate>

      <!-- Name -->
      <div class="field">
        <label for="name">Full name *</label>
        <input id="name" type="text" formControlName="name"
               autocomplete="name" />
        <span class="error" *ngIf="showErr('name')">Name is required.</span>
      </div>

      <!-- Email -->
      <div class="field">
        <label for="email">Email *</label>
        <input id="email" type="email" formControlName="email"
               autocomplete="email" />
        <span class="error" *ngIf="showErr('email')">
          Valid email required.
        </span>
      </div>

      <!-- Password -->
      <div class="field">
        <label for="pw">Password * (min 8 characters)</label>
        <input id="pw" type="password" formControlName="password"
               autocomplete="new-password" />
        <span class="error" *ngIf="showErr('password')">
          At least 8 characters required.
        </span>
      </div>

      <!-- Age -->
      <div class="field">
        <label for="age">Age</label>
        <input id="age" type="number" formControlName="age"
               min="13" max="120" inputmode="numeric" />
      </div>

      <!-- Birthday -->
      <div class="field">
        <label for="dob">Date of birth</label>
        <input id="dob" type="date" formControlName="dob"
               max="2010-01-01" />
      </div>

      <!-- Plan (radio) -->
      <fieldset formGroupName="plan">
        <legend>Plan *</legend>
        <label><input type="radio" value="free"  formControlName="tier" /> Free</label>
        <label><input type="radio" value="pro"   formControlName="tier" /> Pro</label>
        <label><input type="radio" value="team"  formControlName="tier" /> Team</label>
      </fieldset>

      <!-- Notifications (checkbox) -->
      <label class="checkbox">
        <input type="checkbox" formControlName="notify" />
        Send me product updates
      </label>

      <!-- Avatar (file — reactive approach) -->
      <div class="field">
        <label>Avatar (PNG or JPEG, max 2 MB)</label>
        <input type="file" accept="image/png,image/jpeg"
               (change)="onAvatar($event)" />
        <span class="error" *ngIf="avatarError()">{{ avatarError() }}</span>
      </div>

      <button type="submit" [disabled]="form.invalid || submitting()">
        {{ submitting() ? 'Creating account…' : 'Create account' }}
      </button>
    </form>
  `,
})
export class RegisterComponent {
  private fb = inject(FormBuilder);

  form = this.fb.group({
    name:     ['', Validators.required],
    email:    ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(8)]],
    age:      [null as number | null],
    dob:      [''],
    plan:     this.fb.group({
      tier: ['free', Validators.required],
    }),
    notify: [false],
  });

  submitting = signal(false);
  avatarError = signal<string | null>(null);
  avatarFile: File | null = null;

  showErr(name: string): boolean {
    const c = this.form.get(name);
    return !!(c?.invalid && c?.touched);
  }

  onAvatar(event: Event): void {
    const input = event.target as HTMLInputElement;
    const file = input.files?.[0];
    if (!file) return;
    if (file.size > 2 * 1024 * 1024) {
      this.avatarError.set('File exceeds 2 MB limit.');
      input.value = '';
      this.avatarFile = null;
      return;
    }
    this.avatarError.set(null);
    this.avatarFile = file;
  }

  async onSubmit(): Promise<void> {
    if (this.form.invalid || this.submitting()) return;
    this.form.markAllAsTouched();
    this.submitting.set(true);
    try {
      // Build FormData if avatar present
      const payload = new FormData();
      payload.append('data', JSON.stringify(this.form.value));
      if (this.avatarFile) payload.append('avatar', this.avatarFile);
      // await this.authService.register(payload).toPromise();
      console.log('Submitted', this.form.value);
    } finally {
      this.submitting.set(false);
    }
  }
}
